export const DraggableNode = ({ type, label, icon: Icon, color = 'primary' }) => {
  const onDragStart = (event, nodeType) => {
    const appData = { nodeType }
    event.dataTransfer.setData('application/reactflow', JSON.stringify(appData));
    event.dataTransfer.effectAllowed = 'move';
  };

  const variantMap = {
    solid: {
      primary: 'bg-primary border-primary/20 text-white shadow-neon-primary',
      emerald: 'bg-emerald-500/20 border-emerald-500/20 text-emerald-400',
      rose: 'bg-rose-500/20 border-rose-500/20 text-rose-400',
      violet: 'bg-violet-500/60 border-violet-500/20 text-white shadow-neon-violet',
    },
    outline: {
      sky: 'bg-sky-500/5 border-sky-500/20 text-sky-400 hover:bg-sky-500/10',
      amber: 'bg-amber-500/5 border-amber-500/20 text-amber-400 hover:bg-amber-500/10',
      violet: 'bg-violet-500/5 border-violet-500/20 text-violet-400 hover:bg-violet-500/10',
    }
  };

  const variant = ['customInput', 'customOutput', 'text', 'llm'].includes(type) ? 'solid' : 'outline';
  const colorClass = variantMap[variant][color] || variantMap.solid.primary;

  return (
    <div
      className={`cursor-grab flex flex-col items-center justify-center min-w-[80px] h-24 p-4 rounded-2xl border transition-all duration-300 hover:scale-[1.02] active:scale-95 group ${colorClass}`}
      onDragStart={(event) => onDragStart(event, type)}
      onDragEnd={(event) => (event.target.style.cursor = 'grab')}
      draggable
    >
      <div className="mb-2 group-hover:scale-110 transition-transform duration-300">
        {Icon && <Icon className="w-6 h-6" />}
      </div>
      <span className="text-[14px] font-bold uppercase tracking-wider">{label}</span>
    </div>
  );
};
